// ============================================================
// services/api.js — Centralized Axios API Client
// ============================================================
// All HTTP calls to the backend go through this file.
// This ensures:
//   1. Base URL is set in one place (easy to change)
//   2. JWT token is automatically added to every request
//   3. Error handling is consistent
// ============================================================

import axios from "axios";

// Read the API base URL from the React .env file
const BASE_URL = process.env.REACT_APP_API_URL || "http://localhost:8000/api";

// Create a reusable axios instance
const api = axios.create({
  baseURL: BASE_URL,
  headers: {
    "Content-Type": "application/json",
  },
});

// ---- Request Interceptor ----
// Automatically attach the JWT token to every outgoing request
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem("token"); // Retrieve stored token
    if (token) {
      config.headers.Authorization = `Bearer ${token}`; // Add to header
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// ---- Response Interceptor ----
// If the server returns 401 (Unauthorized), log the user out
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      // Token expired or invalid — clear storage and redirect to login
      localStorage.clear();
      window.location.href = "/login";
    }
    return Promise.reject(error);
  }
);

// ============================================================
// AUTH APIs
// ============================================================

export const authAPI = {
  /** Register a new merchant */
  register: (data) => api.post("/auth/register", data),

  /** Login as merchant, returns JWT */
  login: (email, password) => api.post("/auth/login", { email, password }),

  /** Login as admin, returns JWT */
  adminLogin: (email, password) => api.post("/auth/admin/login", { email, password }),
};

// ============================================================
// APPLICATION APIs (Merchant)
// ============================================================

export const applicationAPI = {
  /** Submit onboarding application */
  submit: () => api.post("/application/submit"),

  /** Check current application status */
  getStatus: () => api.get("/application/status"),
};

// ============================================================
// DOCUMENT UPLOAD API
// ============================================================

export const uploadAPI = {
  /**
   * Upload a document file.
   * Must use FormData (not JSON) for file uploads.
   * 
   * @param {string} docType  - One of: pan_card, gst_certificate, bank_statement, company_registration
   * @param {File}   file     - The selected file object from <input type="file">
   */
  uploadDocument: (docType, file) => {
    const formData = new FormData();
    formData.append("doc_type", docType);
    formData.append("file", file);

    return api.post("/upload/document", formData, {
      headers: { "Content-Type": "multipart/form-data" }, // Override JSON header
    });
  },
};

// ============================================================
// ADMIN APIs
// ============================================================

export const adminAPI = {
  /**
   * Get all applications with optional filters.
   * @param {object} params - { status, search, skip, limit }
   */
  getAllApplications: (params = {}) => api.get("/admin/applications", { params }),

  /** Get a single application by ID */
  getApplication: (id) => api.get(`/admin/applications/${id}`),

  /**
   * Update application status and remarks.
   * @param {number} id
   * @param {string} status  - "pending" | "under_review" | "approved" | "rejected"
   * @param {string} remarks - Optional admin comment
   */
  updateStatus: (id, status, remarks) =>
    api.put(`/admin/applications/${id}/status`, { status, remarks }),
};

export default api;
